<?php

namespace App\Services\Tenancy;

use App\Models\Tenancy\Subscription;
use App\Support\Tenancy\TenantThemeSettings;
use Illuminate\Support\Facades\Storage;

/**
 * Generates and manages the per-tenant theme CSS file.
 *
 * Output file  : storage/app/public/tenant-themes/{subscription_id}.css
 * Public URL   : {APP_URL}/storage/tenant-themes/{subscription_id}.css
 *
 * The generated file defines CSS custom properties on :root and
 * utility classes (bg-theme-*, text-theme-*, btn-theme-*) that
 * section templates can consume.
 */
class TenantThemeCssGenerator
{
    private const DISK = 'public';
    private const DIRECTORY = 'tenant-themes';

    // -----------------------------------------------------------------------
    // Public API
    // -----------------------------------------------------------------------

    /**
     * Regenerate the CSS file for the given subscription.
     * Creates the directory if it does not exist.
     */
    public function generate(Subscription $subscription): string
    {
        $theme = TenantThemeSettings::fromArray(
            is_array($subscription->theme_settings) ? $subscription->theme_settings : []
        );

        $css = $this->buildCss($theme);

        Storage::disk(self::DISK)->put($this->relativePath($subscription->id), $css);

        return $css;
    }

    /**
     * Delete the CSS file for a subscription (e.g. on subscription deletion).
     */
    public function delete(int $subscriptionId): void
    {
        $path = $this->relativePath($subscriptionId);

        if (Storage::disk(self::DISK)->exists($path)) {
            Storage::disk(self::DISK)->delete($path);
        }
    }

    /**
     * Absolute filesystem path (useful for artisan commands / tests).
     */
    public function absolutePath(int $subscriptionId): string
    {
        return Storage::disk(self::DISK)->path($this->relativePath($subscriptionId));
    }

    /**
     * Public URL to the CSS file, or null if the file does not exist.
     */
    public function urlIfExists(int $subscriptionId): ?string
    {
        $path = $this->relativePath($subscriptionId);

        if (! Storage::disk(self::DISK)->exists($path)) {
            return null;
        }

        return Storage::disk(self::DISK)->url($path);
    }

    /**
     * Public URL (unconditional — use when you know the file exists or for
     * injecting into layouts after generation).
     */
    public function url(int $subscriptionId): string
    {
        return Storage::disk(self::DISK)->url($this->relativePath($subscriptionId));
    }

    /**
     * Static helper for Blade views and controllers.
     *
     * Returns the public URL to the generated tenant theme CSS file
     * if it exists, or null if the file has not been generated yet
     * or if no subscription is provided.
     *
     * Usage in Blade:
     *   @php $themeUrl = \App\Services\Tenancy\TenantThemeCssGenerator::publicUrlFor($subscription); @endphp
     *   @if ($themeUrl) <link rel="stylesheet" href="{{ $themeUrl }}"> @endif
     */
    public static function publicUrlFor(?Subscription $subscription): ?string
    {
        if ($subscription === null || ! isset($subscription->id)) {
            return null;
        }

        $path = self::DIRECTORY . '/' . $subscription->id . '.css';

        if (! Storage::disk(self::DISK)->exists($path)) {
            return null;
        }

        return Storage::disk(self::DISK)->url($path);
    }

    // -----------------------------------------------------------------------
    // Internal helpers
    // -----------------------------------------------------------------------

    private function relativePath(int $subscriptionId): string
    {
        return self::DIRECTORY . '/' . $subscriptionId . '.css';
    }

    private function buildCss(TenantThemeSettings $t): string
    {
        $lines = [];

        // ------------------------------------------------------------------
        // 1. CSS custom properties (:root)
        // ------------------------------------------------------------------
        $lines[] = '/* Tenant theme — generated by TenantThemeCssGenerator */';
        $lines[] = ':root {';

        // Colors
        $lines[] = "  /* --- Colors --- */";
        $lines[] = "  --theme-color-primary:   {$t->colorPrimary};";
        $lines[] = "  --theme-color-secondary: {$t->colorSecondary};";
        $lines[] = "  --theme-color-surface:   {$t->colorSurface};";
        $lines[] = "  --theme-color-muted:     {$t->colorMuted};";
        $lines[] = "  --theme-color-heading:   {$t->colorHeading};";
        $lines[] = "  --theme-color-body:      {$t->colorBody};";
        $lines[] = "  --theme-color-border:    {$t->colorBorder};";

        // Typography
        $lines[] = "";
        $lines[] = "  /* --- Typography --- */";
        $lines[] = "  --theme-font-primary:    {$t->fontPrimary};";
        $lines[] = "  --theme-font-heading:    {$t->fontHeading};";
        $lines[] = "  --theme-font-size-base:  {$t->baseFontSize};";
        $lines[] = "  --theme-weight-normal:   {$t->weightNormal};";
        $lines[] = "  --theme-weight-bold:     {$t->weightBold};";

        // Shape
        $lines[] = "";
        $lines[] = "  /* --- Shape / Radius --- */";
        $lines[] = "  --theme-radius-sm:       {$t->radiusSm};";
        $lines[] = "  --theme-radius-md:       {$t->radiusMd};";
        $lines[] = "  --theme-radius-lg:       {$t->radiusLg};";
        $lines[] = "  --theme-radius-xl:       {$t->radiusXl};";

        // Buttons
        $lines[] = "";
        $lines[] = "  /* --- Buttons --- */";
        $lines[] = "  --theme-button-radius:   {$t->buttonRadius};";
        $lines[] = '}';
        $lines[] = '';

        // ------------------------------------------------------------------
        // 2. Semantic utility classes (background)
        // ------------------------------------------------------------------
        $lines[] = '/* --- Background utilities --- */';
        $lines[] = '.bg-theme-primary   { background-color: var(--theme-color-primary) !important; }';
        $lines[] = '.bg-theme-secondary { background-color: var(--theme-color-secondary) !important; }';
        $lines[] = '.bg-theme-surface   { background-color: var(--theme-color-surface) !important; }';
        $lines[] = '.bg-theme-muted     { background-color: var(--theme-color-muted) !important; }';
        $lines[] = '';

        // ------------------------------------------------------------------
        // 3. Semantic utility classes (text)
        // ------------------------------------------------------------------
        $lines[] = '/* --- Text utilities --- */';
        $lines[] = '.text-theme-primary   { color: var(--theme-color-primary) !important; }';
        $lines[] = '.text-theme-secondary { color: var(--theme-color-secondary) !important; }';
        $lines[] = '.text-theme-heading   { color: var(--theme-color-heading) !important; }';
        $lines[] = '.text-theme-body      { color: var(--theme-color-body) !important; }';
        $lines[] = '.text-theme-muted     { color: var(--theme-color-muted) !important; }';
        $lines[] = '';

        // ------------------------------------------------------------------
        // 4. Border utilities
        // ------------------------------------------------------------------
        $lines[] = '/* --- Border utilities --- */';
        $lines[] = '.border-theme-primary { border-color: var(--theme-color-primary) !important; }';
        $lines[] = '.border-theme-border  { border-color: var(--theme-color-border) !important; }';
        $lines[] = '';

        // ------------------------------------------------------------------
        // 5. Button utilities (style-dependent)
        // ------------------------------------------------------------------
        $lines[] = '/* --- Button utilities --- */';

        if ($t->buttonStyle === 'filled') {
            $lines[] = '.btn-theme-primary {';
            $lines[] = '  display: inline-flex; align-items: center; justify-content: center;';
            $lines[] = '  background-color: var(--theme-color-primary);';
            $lines[] = '  color: #ffffff;';
            $lines[] = '  border: 2px solid transparent;';
            $lines[] = '  border-radius: var(--theme-button-radius);';
            $lines[] = '  font-family: var(--theme-font-primary);';
            $lines[] = '  font-weight: var(--theme-weight-bold);';
            $lines[] = '  padding: 0.625rem 1.5rem;';
            $lines[] = '  transition: opacity 0.15s ease, transform 0.1s ease;';
            $lines[] = '  cursor: pointer; text-decoration: none;';
            $lines[] = '}';
            $lines[] = '.btn-theme-primary:hover { opacity: 0.88; }';
            $lines[] = '.btn-theme-primary:active { transform: scale(0.97); }';

            $lines[] = '';
            $lines[] = '.btn-theme-secondary {';
            $lines[] = '  display: inline-flex; align-items: center; justify-content: center;';
            $lines[] = '  background-color: var(--theme-color-secondary);';
            $lines[] = '  color: #ffffff;';
            $lines[] = '  border: 2px solid transparent;';
            $lines[] = '  border-radius: var(--theme-button-radius);';
            $lines[] = '  font-family: var(--theme-font-primary);';
            $lines[] = '  font-weight: var(--theme-weight-bold);';
            $lines[] = '  padding: 0.625rem 1.5rem;';
            $lines[] = '  transition: opacity 0.15s ease, transform 0.1s ease;';
            $lines[] = '  cursor: pointer; text-decoration: none;';
            $lines[] = '}';
            $lines[] = '.btn-theme-secondary:hover { opacity: 0.88; }';
            $lines[] = '.btn-theme-secondary:active { transform: scale(0.97); }';

        } elseif ($t->buttonStyle === 'outline') {
            $lines[] = '.btn-theme-primary {';
            $lines[] = '  display: inline-flex; align-items: center; justify-content: center;';
            $lines[] = '  background-color: transparent;';
            $lines[] = '  color: var(--theme-color-primary);';
            $lines[] = '  border: 2px solid var(--theme-color-primary);';
            $lines[] = '  border-radius: var(--theme-button-radius);';
            $lines[] = '  font-family: var(--theme-font-primary);';
            $lines[] = '  font-weight: var(--theme-weight-bold);';
            $lines[] = '  padding: 0.625rem 1.5rem;';
            $lines[] = '  transition: background-color 0.15s ease, color 0.15s ease, transform 0.1s ease;';
            $lines[] = '  cursor: pointer; text-decoration: none;';
            $lines[] = '}';
            $lines[] = '.btn-theme-primary:hover { background-color: var(--theme-color-primary); color: #ffffff; }';
            $lines[] = '.btn-theme-primary:active { transform: scale(0.97); }';

            $lines[] = '';
            $lines[] = '.btn-theme-secondary {';
            $lines[] = '  display: inline-flex; align-items: center; justify-content: center;';
            $lines[] = '  background-color: transparent;';
            $lines[] = '  color: var(--theme-color-secondary);';
            $lines[] = '  border: 2px solid var(--theme-color-secondary);';
            $lines[] = '  border-radius: var(--theme-button-radius);';
            $lines[] = '  font-family: var(--theme-font-primary);';
            $lines[] = '  font-weight: var(--theme-weight-bold);';
            $lines[] = '  padding: 0.625rem 1.5rem;';
            $lines[] = '  transition: background-color 0.15s ease, color 0.15s ease, transform 0.1s ease;';
            $lines[] = '  cursor: pointer; text-decoration: none;';
            $lines[] = '}';
            $lines[] = '.btn-theme-secondary:hover { background-color: var(--theme-color-secondary); color: #ffffff; }';
            $lines[] = '.btn-theme-secondary:active { transform: scale(0.97); }';

        } else {
            // ghost
            $lines[] = '.btn-theme-primary {';
            $lines[] = '  display: inline-flex; align-items: center; justify-content: center;';
            $lines[] = '  background-color: transparent;';
            $lines[] = '  color: var(--theme-color-primary);';
            $lines[] = '  border: 2px solid transparent;';
            $lines[] = '  border-radius: var(--theme-button-radius);';
            $lines[] = '  font-family: var(--theme-font-primary);';
            $lines[] = '  font-weight: var(--theme-weight-bold);';
            $lines[] = '  padding: 0.625rem 1.5rem;';
            $lines[] = '  transition: background-color 0.15s ease, transform 0.1s ease;';
            $lines[] = '  cursor: pointer; text-decoration: none;';
            $lines[] = '}';
            $lines[] = '.btn-theme-primary:hover { background-color: color-mix(in srgb, var(--theme-color-primary) 10%, transparent); }';
            $lines[] = '.btn-theme-primary:active { transform: scale(0.97); }';

            $lines[] = '';
            $lines[] = '.btn-theme-secondary {';
            $lines[] = '  display: inline-flex; align-items: center; justify-content: center;';
            $lines[] = '  background-color: transparent;';
            $lines[] = '  color: var(--theme-color-secondary);';
            $lines[] = '  border: 2px solid transparent;';
            $lines[] = '  border-radius: var(--theme-button-radius);';
            $lines[] = '  font-family: var(--theme-font-primary);';
            $lines[] = '  font-weight: var(--theme-weight-bold);';
            $lines[] = '  padding: 0.625rem 1.5rem;';
            $lines[] = '  transition: background-color 0.15s ease, transform 0.1s ease;';
            $lines[] = '  cursor: pointer; text-decoration: none;';
            $lines[] = '}';
            $lines[] = '.btn-theme-secondary:hover { background-color: color-mix(in srgb, var(--theme-color-secondary) 10%, transparent); }';
            $lines[] = '.btn-theme-secondary:active { transform: scale(0.97); }';
        }

        $lines[] = '';

        // ------------------------------------------------------------------
        // 6. Typography base
        // ------------------------------------------------------------------
        $lines[] = '/* --- Typography base --- */';
        $lines[] = '.font-theme-primary { font-family: var(--theme-font-primary) !important; }';
        $lines[] = '.font-theme-heading { font-family: var(--theme-font-heading) !important; }';
        $lines[] = '';

        // ------------------------------------------------------------------
        // 7. Radius utilities
        // ------------------------------------------------------------------
        $lines[] = '/* --- Radius utilities --- */';
        $lines[] = '.rounded-theme-sm { border-radius: var(--theme-radius-sm) !important; }';
        $lines[] = '.rounded-theme-md { border-radius: var(--theme-radius-md) !important; }';
        $lines[] = '.rounded-theme-lg { border-radius: var(--theme-radius-lg) !important; }';
        $lines[] = '.rounded-theme-xl { border-radius: var(--theme-radius-xl) !important; }';
        $lines[] = '';

        return implode("\n", $lines);
    }
}
